import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { MinusCircle, Plus, AlertTriangle, Filter } from 'lucide-react';
import '../styles/Despesas.css';

const Despesas = () => {
  const [lista, setLista] = useState([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ descricao: '', valor: '', categoria: 'Moradia', data: new Date().toISOString().split('T')[0] });

  useEffect(() => {
    buscarDespesas();
  }, []);

  async function buscarDespesas() {
    setLoading(true);
    const { data } = await supabase.from('despesas').select('*').order('data_vencimento', { ascending: false });
    setLista(data || []);
    setLoading(false);
  }

  async function handleSalvar(e) {
    e.preventDefault();
    const { data: { user } } = await supabase.auth.getUser();
    
    const { error } = await supabase.from('despesas').insert([{
      user_id: user.id,
      descricao: form.descricao,
      valor: parseFloat(form.valor),
      categoria: form.categoria,
      data_vencimento: form.data
    }]);

    if (!error) {
      setForm({ ...form, descricao: '', valor: '' });
      buscarDespesas();
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });

  return (
    <div className="despesas-container fade-in">
      <header className="despesas-header">
        <div>
          <h2>Despesas e Custos</h2>
          <p>Controle de gastos fixos e variáveis</p>
        </div>
        <div className="icon-badge-expense"><MinusCircle size={32} color="#ef4444" /></div>
      </header>

      <div className="despesas-grid">
        <div className="despesas-card form-section">
          <h3>Lançar Gasto</h3>
          <form onSubmit={handleSalvar}>
            <div className="input-group">
              <label>Item / Serviço</label>
              <input type="text" required value={form.descricao} onChange={e => setForm({...form, descricao: e.target.value})} placeholder="Ex: Internet" />
            </div>
            <div className="input-group">
              <label>Valor</label>
              <input type="number" step="0.01" required value={form.valor} onChange={e => setForm({...form, valor: e.target.value})} placeholder="R$ 0,00" />
            </div>
            <div className="input-group">
              <label>Categoria (Orçamento)</label>
              <select value={form.categoria} onChange={e => setForm({...form, categoria: e.target.value})}>
                <option value="Moradia">Moradia</option>
                <option value="Alimentação">Alimentação</option>
                <option value="Lazer">Lazer</option>
                <option value="Saúde">Saúde</option>
                <option value="Educação">Educação</option>
              </select>
            </div>
            <div className="input-group">
              <label>Vencimento</label>
              <input type="date" required value={form.data} onChange={e => setForm({...form, data: e.target.value})} />
            </div>
            <button type="submit" className="btn-add-expense"><Plus size={20} /> Adicionar Despesa</button>
          </form>
        </div>

        <div className="despesas-card list-section">
          <div className="list-header">
            <h3>Lista de Despesas</h3>
            <Filter size={18} color="#94a3b8" />
          </div>
          <div className="scroll-list">
            {loading ? <p>Carregando...</p> : lista.map(item => (
              <div key={item.id} className="expense-item">
                <div className="expense-info">
                  <span className="exp-desc">{item.descricao}</span>
                  <span className="exp-cat">{item.categoria} • {new Date(item.data_vencimento).toLocaleDateString()}</span>
                </div>
                <span className="exp-value">{formatMoney(item.valor)}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Despesas;
